import { Stage } from "./Stage"

export default class extends Stage {
    protected *G(): Generator<void, void, unknown> {
        yield* this.wait(30)

        yield* this.text("「……機械大戦、か。」", { name: "マス" })
        yield* this.text("俺は大昔に読んだ教科書の一節をぼんやりと思い出した。")

        yield* this.text("機械大戦の始まりは「局所的な民族差別に由来する憎悪」だったと今では云われている。")
        yield* this.text("その憎悪はアルゴリズムによって増幅され、民主主義は民意の儘に人類を世界大戦へと導いた。")
        yield* this.text("人はお互いの影を恐れ、SILOは、願われて生まれた。")

        yield* this.text("機械大戦の罪は戦争成立要件に「人命の損失」を必要としたことだろう。")
        yield* this.text("機械大戦は別名「人の死なない戦争」とも呼ばれている。")
        yield* this.text("長く続き過ぎた戦争と増え過ぎた人口は地球を疲弊させた。")
        yield* this.text("そのため、戦後結ばれた条約により自律兵器の使用は全面的に禁止、及び客観的に人命の損失が発生しない戦闘は戦争と認められないこととなった。")

        yield* this.text("（それがこいつの正体だろ?）", { name: "マス" })
        yield* this.text("俺は隣に座る少女の顔を見た。")
        yield* this.text("（だがこの戦いは戦争じゃない。SILOに反対する内乱だ。人柱は必要だったのか?）", { name: "マス" })

        // yield* this.text("戦争の長期化を防ぐ、というのが建前であり本音でもあるが、本来の目的はインフラ施設の保護である。")
        // yield* this.text("インフラの崩壊こそが、最も人命の損失を生むのだから。")
    }
}
